6.query:
fetch logs
| filter log.source == "Kong Konnect"
| makeTimeseries cnt = count(), interval:1h, by:{konnect_format}

8.query:
fetch logs
| filter log.source == "Kong Konnect" and konnect_format == "authentication"
| summarize cnt = count(), by:{name}

9.query:
fetch logs
| filter log.source == "Kong Konnect" and konnect_format == "authentication"
| summarize cnt = count(), by:{event_class_id}
